import{_ as a,o as t,c as i,ae as l}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"Branch Plan: SDK Unified + MCP Server","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/branch_sdk_mcp.md","filePath":"docs/plans/branch_sdk_mcp.md"}'),r={name:"docs/plans/branch_sdk_mcp.md"};function o(n,e,s,c,d,p){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="branch-plan-sdk-unified-mcp-server" tabindex="-1">Branch Plan: SDK Unified + MCP Server <a class="header-anchor" href="#branch-plan-sdk-unified-mcp-server" aria-label="Permalink to &quot;Branch Plan: SDK Unified + MCP Server&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Ship a unified SDK and a local MCP wrapper so each agent can operate via a stable API that abstracts proof, credit state, and payments.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>SDK package with modules: identity, credit_state, shadowwire, privacycash, receipts.</li><li>Local MCP wrapper exposing tools like: agent.credit, agent.transfer_private, agent.pay, agent.status, agent.receipts.list, agent.receipts.latest, agent.state.get.</li><li>MCP is tied to the agent runtime (CLI/local/devbox); not a shared multi-tenant backend.</li><li>Thin orchestration over other branches (no heavy business logic here); MCP just surfaces SDK/agent actions.</li><li>Orchestrate sequence: gateway -&gt; payment -&gt; receipt.</li><li>ShadowWire wallet signature requirement handled by SDK wrapper.</li></ul><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>On-chain program implementation.</li><li>Payment rail implementation details.</li><li>Helius integration or receipts wiring (handled in Infra branch).</li><li>Multi-tenant MCP service; defer to a future enterprise/gateway mode.</li></ul><h2 id="milestones" tabindex="-1">Milestones <a class="header-anchor" href="#milestones" aria-label="Permalink to &quot;Milestones&quot;">​</a></h2><ol><li>SDK skeleton + configs + example usage.</li><li>MCP server running with tool definitions.</li><li>End-to-end call from MCP to SDK adapters following gateway -&gt; payment -&gt; receipt.</li></ol><h2 id="adapter-expectations" tabindex="-1">Adapter Expectations <a class="header-anchor" href="#adapter-expectations" aria-label="Permalink to &quot;Adapter Expectations&quot;">​</a></h2><ul><li>ShadowWire adapter must accept a <code>wallet.signMessage</code> hook and enforce transfer <code>type</code>.</li><li>payment_request.currency maps to ShadowWire <code>token</code> (USD1 default).</li><li>If ShadowWire throws <code>RecipientNotFoundError</code>, fallback to <code>external</code> transfer.</li><li>Privacy Cash adapter should implement <code>deposit</code> + <code>withdraw</code> (SOL) and <code>depositSPL</code> + <code>withdrawSPL</code> (SPL).</li><li>Privacy Cash requires <code>RPC_url</code> and <code>owner</code> in client setup.</li><li>Privacy Cash returns <code>tx</code> on deposit/withdraw; map to <code>payment_result.tx_sig</code>.</li></ul><h2 id="mcp-data-access-expectations" tabindex="-1">MCP Data Access Expectations <a class="header-anchor" href="#mcp-data-access-expectations" aria-label="Permalink to &quot;MCP Data Access Expectations&quot;">​</a></h2><ul><li>MCP should expose recent receipts (latest and list) via SDK receipts module.</li><li>MCP should expose latest agent state/credit snapshot for tooling (read-only).</li></ul><h2 id="deliverables" tabindex="-1">Deliverables <a class="header-anchor" href="#deliverables" aria-label="Permalink to &quot;Deliverables&quot;">​</a></h2><ul><li>SDK package with types and minimal docs.</li><li>MCP server with tool registry and example prompts.</li><li>Demo script that triggers one full flow.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Interfaces from Core Program and Payments branches.</li><li>RPC config (Helius endpoint preferred).</li></ul><h2 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h2><ul><li>MCP tool surface too broad or unstable.</li><li>Version drift between SDK adapters.</li><li>Integration note: other branches implementing <code>ReceiptStore</code> must add <code>listReceipts</code> + <code>getLatestReceipt</code>.</li></ul><h2 id="fallback" tabindex="-1">Fallback <a class="header-anchor" href="#fallback" aria-label="Permalink to &quot;Fallback&quot;">​</a></h2><ul><li>Expose minimal tool set (credit + transfer) and defer advanced flows.</li></ul><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><ul><li>BP1: SDK usage example runs locally.</li><li>BP2: MCP server answers a tool call.</li><li>BP3: MCP tool triggers a real payment flow.</li></ul>',23)])])}const m=a(r,[["render",o]]);export{u as __pageData,m as default};
